import React from "react";

const TaskCard = ({
  title = "No Title",
  description = "",
  priority = "Low", // Значення за замовчуванням
  status = "Not Started", // Значення за замовчуванням
  date = "",
  image,
  type = "",
}) => {
  // Або використовуй перевірку безпосередньо в рендері:
  const statusClass = status?.toLowerCase().replace(" ", "-") || "not-started";
  const priorityClass = priority?.toLowerCase() || "low";

  return (
    <div className={`task-card ${type}`}>
      <div className="task-card-header">
        <div className="task-checkbox-wrapper">
          <span className={`status-dot ${statusClass}`}></span>
          <h4>{title}</h4>
        </div>
        <button className="more-btn">•••</button>
      </div>

      <p className="task-desc">{description}</p>

      <div className="task-footer">
        {image && (
          <img src={image} alt="task attachment" className="task-img" />
        )}
        <div className="task-meta">
          <span>
            Priority: <strong className={priorityClass}>{priority}</strong>
          </span>
          <span>
            Status: <strong className={statusClass}>{status}</strong>
          </span>
          <span className="task-date">Created on: {date}</span>
        </div>
      </div>
    </div>
  );
};

export default TaskCard;
